// Verify Fathom webhook signature
const crypto = require('crypto');

const secret = process.env.FATHOM_WEBHOOK_SECRET || '';
const body = JSON.stringify($input.first().json.body || $input.first().json);
const webhookId = $input.first().headers['webhook-id'] || '';
const webhookTimestamp = $input.first().headers['webhook-timestamp'] || '';
const webhookSig = $input.first().headers['webhook-signature'] || '';

// Fathom uses svix signing: "webhook-id.webhook-timestamp.body"
const toSign = `${webhookId}.${webhookTimestamp}.${body}`;

// Secret comes as whsec_<base64> — strip prefix and decode
const secretBytes = Buffer.from(secret.replace('whsec_', ''), 'base64');
const computedSig = crypto.createHmac('sha256', secretBytes).update(toSign).digest('base64');

// Signature header can have multiple: "v1,<sig1> v1,<sig2>"
const sigs = webhookSig.split(' ').map(s => s.replace('v1,', ''));
const valid = sigs.some(s => s === computedSig);

if (!valid) {
  throw new Error('Invalid Fathom webhook signature');
}

return $input.all();

const data = $input.first().json;
const body = data.body || data;

// Extract meeting title as prospect name (calendar event title)
const meetingTitle = body.meeting_title || body.title || '';

// Extract summary text
let summaryText = '';
if (body.default_summary) {
  if (typeof body.default_summary === 'string') {
    summaryText = body.default_summary;
  } else if (body.default_summary.summary) {
    summaryText = body.default_summary.summary;
  } else if (body.default_summary.text) {
    summaryText = body.default_summary.text;
  }
}

// Call date from scheduled start or recording start
const callDate = (body.scheduled_start_time || body.recording_start_time || '').slice(0, 10);

// Action items
const actionItems = body.action_items || null;

// Attendees
const attendees = body.calendar_invitees || null;

// Transcript
const transcript = body.transcript || null;

// Recording ID and URL
const fathomRecordingId = body.recording_id || null;
const fathomUrl = body.url || body.share_url || null;

return [{
  json: {
    prospect_name: meetingTitle,
    call_date: callDate || null,
    notes: summaryText,
    summary: summaryText,
    transcript: transcript ? JSON.stringify(transcript) : null,
    action_items: actionItems ? JSON.stringify(actionItems) : null,
    attendees: attendees ? JSON.stringify(attendees) : null,
    fathom_recording_id: fathomRecordingId,
    fathom_url: fathomUrl,
    qualified: false,
    closed: false
  }
}];

